export function getAllSJFactories() {
  return Object.values(SJ_FASHION_FACTORIES_BY_COUNTRY).flat();
}

export function getTopSJFactories(n = 20) {
  return getAllSJFactories().slice(0, n);
}

export function getSJVendorNames(country) {
  const src = country ? SJ_FASHION_FACTORIES_BY_COUNTRY[country] : getAllSJFactories();
  return (src || []).map(f => f.name);
}
